-- ─── CHECKLIST ITEMS ───────────────────────────────────────
INSERT OR IGNORE INTO ess_checklist_items (id, section_id, label, sort_order) VALUES
  ('ess_i1_01', 'ess_s1_1', 'Define and distinguish between ecocentric, anthropocentric, and technocentric environmental value systems', 1),
  ('ess_i1_02', 'ess_s1_1', 'Explain how cultural, economic, and social context influences environmental value systems', 2),
  ('ess_i1_03', 'ess_s1_2', 'Define a system and identify inputs, outputs, storages, and flows', 3),
  ('ess_i1_04', 'ess_s1_2', 'Distinguish between open, closed, and isolated systems with examples', 4),
  ('ess_i1_05', 'ess_s1_2', 'Explain positive and negative feedback loops with environmental examples', 5),
  ('ess_i1_06', 'ess_s1_3', 'Define equilibrium (steady-state and static) and explain tipping points', 6),
  ('ess_i1_07', 'ess_s1_3', 'Explain the concept of system resilience and how it relates to feedback loops', 7),
  ('ess_i1_08', 'ess_s1_4', 'Define sustainability and explain its environmental, social, and economic dimensions', 8),
  ('ess_i1_09', 'ess_s1_4', 'Distinguish between renewable and non-renewable natural capital', 9),
  ('ess_i1_10', 'ess_s1_4', 'Explain the concept of an ecological footprint and its significance', 10),
  ('ess_i1_11', 'ess_s1_5', 'Describe the strengths and limitations of using models in ESS', 11),
  ('ess_i1_12', 'ess_s1_5', 'Apply systems thinking to analyze environmental issues', 12),
  ('ess_i1_13', 'ess_s1_5', 'Distinguish between pollution, contamination, and degradation', 13),
  ('ess_i1_14', 'ess_s1_5', 'Explain the precautionary principle and its application in environmental management', 14),
  ('ess_i1_15', 'ess_s1_5', 'Describe transfers and transformations of energy and matter within systems', 15),
  ('ess_i1_16', 'ess_s1_5', 'Explain the laws of thermodynamics in an environmental context', 16);

