INSERT OR IGNORE INTO ess_flashcard_topics (id, name, description, unit, card_count, sort_order, color) VALUES
  ('ess_t1', 'Foundations of ESS', 'Key terms and concepts from Unit 1: Environmental Value Systems, Systems and Models, Energy and Equilibria, Sustainability, and Humans and Pollution', '1', 16, 1, '#10B981');

-- ─── FLASHCARDS ────────────────────────────────────────────
INSERT OR IGNORE INTO ess_flashcards (id, topic_id, front, back, sort_order) VALUES
  ('ess_f1_01', 'ess_t1', 'Environmental Value System (EVS)', 'A worldview or set of paradigms that shapes the way an individual or group of people perceives and evaluates environmental issues, influenced by cultural, religious, economic, and socio-political contexts.', 1),
  ('ess_f1_02', 'ess_t1', 'Ecocentrism', 'A value system that places ecology and nature at the center of importance, viewing humans as part of, not separate from, the natural world. Includes deep ecologists.', 2),
  ('ess_f1_03', 'ess_t1', 'Technocentrism', 'A value system centered on technology and its ability to solve environmental problems and control nature. Includes cornucopians and environmental managers.', 3),
  ('ess_f1_04', 'ess_t1', 'Anthropocentrism', 'A value system that places humans at the center of concern, believing the environment should be managed sustainably to serve human needs.', 4),
  ('ess_f1_05', 'ess_t1', 'Open System', 'A system that exchanges both matter and energy with its surroundings. Example: an ecosystem.', 5),
  ('ess_f1_06', 'ess_t1', 'Closed System', 'A system that exchanges energy but not matter with its surroundings. Example: Earth (approximately).', 6),
  ('ess_f1_07', 'ess_t1', 'Isolated System', 'A system that exchanges neither energy nor matter with its surroundings. These are theoretical — none truly exist in nature.', 7),
  ('ess_f1_08', 'ess_t1', 'Positive Feedback Loop', 'A feedback mechanism that amplifies change and moves a system further from its equilibrium. Example: melting ice → less reflection → more warming → more ice melts.', 8),
  ('ess_f1_09', 'ess_t1', 'Negative Feedback Loop', 'A feedback mechanism that counteracts change and returns a system toward equilibrium. Example: increased CO2 → more plant growth → more CO2 absorbed.', 9),
  ('ess_f1_10', 'ess_t1', 'Tipping Point', 'A critical threshold at which a system shifts rapidly from one state to another, often irreversibly. Driven by positive feedback.', 10),
  ('ess_f1_11', 'ess_t1', 'Sustainability', 'Meeting the needs of the present without compromising the ability of future generations to meet their own needs (Brundtland definition).', 11),
  ('ess_f1_12', 'ess_t1', 'Ecological Footprint', 'The area of land and water required to support a defined human population at a given standard of living, measured in global hectares.', 12),
  ('ess_f1_13', 'ess_t1', 'Natural Capital', 'Natural resources and ecosystem services that provide value to humans. Includes renewable (forests, fisheries) and non-renewable (fossil fuels, minerals) resources.', 13),
  ('ess_f1_14', 'ess_t1', 'Steady-State Equilibrium', 'A condition where the inputs and outputs of a system are balanced over time, though small fluctuations may occur.', 14),
  ('ess_f1_15', 'ess_t1', 'Model', 'A simplified representation of reality used to understand systems and make predictions. All models have strengths and limitations.', 15),
  ('ess_f1_16', 'ess_t1', 'Precautionary Principle', 'If an action is suspected to cause harm to the environment, precautionary measures should be taken even if there is no full scientific certainty.', 16);

-- ─── MCQ QUESTIONS ─────────────────────────────────────────
INSERT OR IGNORE INTO ess_mcq_questions (id, question, options, correct_answer, explanation, category, difficulty, unit) VALUES
('ess_m1_01', 'Suggest which of the following might influence a person''s environmental value system:', '["The beliefs of their parents","The country they live in","The level of education they have achieved","All of the above"]', 3, 'All three options are significant in their impact on how a person comes to define their own environmental value system.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_02', 'Improving the energy efficiency of household machines will help us decrease the amount of energy we use. Identify the environmental value system that best matches this approach.', '["Technocentric","Cornucopian","Deep ecologist","Anthropocentric"]', 0, 'A technocentrist believes that technology can solve any environmental problems. More efficient technology is a perfect example of a technocentrist approach to solving the problems created by our ever increasing energy demand.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_03', 'Identify the exchanges that a closed system makes with the environment. I. Energy  II. Matter', '["I only","II only","Both I and II","Neither I nor II"]', 0, 'A closed system exchanges only energy and not matter across its boundaries. The earth could be an example. Solar energy enters the earth''s atmosphere. Some is reflected back to space as is some heat that is reradiated from the surface.', 'Systems and Models', 'easy', '1'),
('ess_m1_04', 'Positive feedback loops ___ while negative feedback loops ___.', '["...continue after a tipping point","...increase resilience in a system","...are mostly good for the environment","...destabilise a system"]', 3, 'Negative feedback loops are generally good in all kinds of systems because they return a system to the original situation, while positive feedback loops move a system away from the original situation.', 'Energy and Equilibria', 'easy', '1'),
('ess_m1_05', 'State which of the following is not accomplished by an Environmental Impact Assessment (EIA).', '["Aiding in the planning and development of a large project","To assess possible impact on the environment a major project might have before it begins","To assess the impacts on the environment a major project has had after it has been operating for a time","To determine ways environmental damage may be reduced or avoided in a major project"]', 2, 'Option C is not one of the reasons to use an EIA as it is a tool that assesses projects before they are started or in their early stages. They are not tools used to assess impact after the fact.', 'Humans and Pollution', 'easy', '1'),
('ess_m1_06', 'In a small wooded area, trees are cut in rotation. If the biomass of the woods is 20,000 kg at the start of one year and the following year it is 24,000 kg, calculate the sustainable yield.', '["20,000","24,000","4,000","2,000"]', 2, 'Sustainable yield = (total biomass at t+1) - (total biomass at t). Sustainable yield = 24,000 - 20,000 = 4,000 kg.', 'Sustainability', 'easy', '1'),
('ess_m1_07', 'Identify which of the following environmental value systems is most likely held by Elon Musk, the founder of Tesla and Space-X.', '["Technocentric","Anthropocentric","Egocentric","Ecocentric"]', 0, 'As Musk is the founder of two huge technology based companies that are both looking at ways to address world issues through better technological advances, it is most likely he has a more technocentric approach.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_08', 'State which of the following is likely to lead an ecosystem to a tipping point.', '["An ecosystem that is in steady state equilibrium","An ecosystem in which negative feedback loops exist","An ecosystem in which positive feedback loops exist","An ecosystem that has diverse, mature trees"]', 2, 'Positive feedback loops amplify change and keep moving the system further and further away from equilibrium until it reaches a tipping point.', 'Energy and Equilibria', 'easy', '1'),
('ess_m1_09', 'Identify the aspect that does not define sustainability.', '["Ecosystems become healthy again after resources are extracted","Natural capital increases","Managing and using resources for human purposes","Nature replenishes all the resources that humans have used"]', 1, 'Natural capital refers to resources found in nature that we can use for goods and services, preferably in a sustainable way. It does not need to increase to be sustainable; it just needs to stay at the same level.', 'Sustainability', 'easy', '1'),
('ess_m1_10', 'Which of the following would not fall under the classification of ecological goods that can produce natural capital?', '["Minerals","Wood","Medicines","Recreation"]', 3, 'Options A, B, and C are common ecological goods that can produce natural capital. They are physical things that we can use. Option D can produce natural capital but is an ecological service, as it is a task that the ecosystem performs.', 'Sustainability', 'easy', '1'),
('ess_m1_11', 'Identify which of the following is not considered a pollutant.', '["Light","Natural gas","Invasive species","Sewage"]', 1, 'A pollutant is something humans add to the environment that has an impact on the organisms in the environment, and that cannot be broken down faster than the rate at which it is being added. Natural gas itself is not a pollutant unless combusted.', 'Humans and Pollution', 'easy', '1'),
('ess_m1_12', 'Identify which country had the largest GDP per capita (income per person) in 2019.', '["Uzbekistan","China","The United States","Qatar"]', 3, 'Option D is correct as Qatar is the furthest country to the right, the axis measuring GDP per capita.', 'Humans and Pollution', 'easy', '1'),
('ess_m1_13', 'When we talk about the environmental movement we are referring to organised groups who take actions to protect the world. State which of the following is not likely to have been a significant historical influence on the environmental movement.', '["The wildlife documentaries by BBC presenter Sir David Attenborough which have been seen by people around the world","Greta Thunberg''s school strikes for the climate, which have been widely publicised","The Blue Marble, a photograph of Earth taken by the Apollo 17 spacecraft crew in December 1972","The extinction of the Tatum Cave beetle sometime since its last sighting in 1965"]', 3, 'While the extinction of a more well-known organism such as the passenger pigeon may inspire people to protect the environment, extinctions of little known species that are not widely publicised are unlikely to affect the environmental movement.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_14', 'Identify the statement that is a priority in a technocentrist worldview.', '["Every human should help decide how to solve environmental problems","All organisms have a right to exist","The outcomes of research should be used to control natural systems","Laws are needed to manage natural systems"]', 2, 'One of the beliefs of technocentrism is that humans should investigate and understand the processes in their surroundings so that they can control them. Option A is incorrect because it is anthropocentric; technocentrists rely on expertise.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_15', 'Using the Figure, deduce which stage of a system would best match participating in a climate demonstration in your city.', '["Stage I","Stage III","Stage IV","Stage V"]', 2, 'Participating in a demonstration reflects you have already thought about your ideas regarding the environment and reflects an action taken with respect to choices you have made. That is considered an output in this model.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_16', 'The North Atlantic right whale is critically endangered. Suggest a technocentric method to save this species from extinction.', '["Changing marine traffic lanes, the main paths that most ships travel along over the ocean","Writing legislation that protects them","Using IVF to help them reproduce","A technocentrist would not try to save a species from extinction"]', 2, 'Option A is ecocentric, as it involves us changing our behaviour to solve a problem. Option B is anthropocentric, as it entails discussion that ends up in consensus in legislation. Option C is technocentric, as it uses technology to solve the problem.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_17', 'A model is a simplified version of reality. Identify which items could best be described as models. I. The human body  II. An office building  III. The atom  IV. The solar system', '["I and II","III and IV","II and IV","All are models"]', 1, 'The model of the atom is used to explain the smallest piece of matter since we cannot actually see them but only detect their properties. The model of the solar system is used to explain the Earth''s surroundings in space.', 'Systems and Models', 'easy', '1'),
('ess_m1_18', 'Identify the correct description for the mesocosms shown in the Figure. Mesocosm 1 / Mesocosm 2', '["Open system, can exchange energy but not matter","Open system, can exchange both matter and energy","Open system, can exchange matter and energy","Isolated system, cannot exchange energy or matter"]', 1, 'The first ecosystem (Mesocosm 1) is open and can exchange both matter and energy, the second ecosystem (Mesocosm 2) is closed and can exchange energy but not matter. Both systems can carry out photosynthesis in the presence of light.', 'Systems and Models', 'easy', '1'),
('ess_m1_19', 'Explain the concept of sustainable development. I. Any development that reduces natural capital is not sustainable. II. Sustainable development meets present needs without compromising future generations. III. Any development that increases the ecological footprint is not considered sustainable.', '["II only","I and II only","III only","I, II and III"]', 3, 'All the options explain the concept of sustainable development.', 'Sustainability', 'easy', '1'),
('ess_m1_20', 'Identify the method that is not a direct method of measuring pollution.', '["Measuring the heavy metal content in soils","Recording the particulate matter in air","Identifying the presence of indicator species in ecosystems","Measuring bacterial content in lake water"]', 2, 'Option C is a measure of species that are pollution tolerant and thus not a direct measure of a pollutant, but rather its effect. Options A, B, and D are all direct measures of pollutants and are thus not correct.', 'Humans and Pollution', 'easy', '1'),
('ess_m1_21', 'List an input and an output of an environmental value system.', '["Perception of nature","Religion","Experiences with nature","Culture"]', 1, 'An environmental value system (EVS) is the combination of values, ideas and arguments about the environment that are held by an individual or group of people. This includes their perception of nature, and thus option A is incorrect as it is an output. Religion is an input.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_22', 'Determine which is the best definition for ''environmental value system'' (EVS).', '["A set of experiences that define what an individual or group believes about the environment","The cultural and socio-political contexts which guide one''s perception of environmental issues","A set of beliefs and ideas about the environment and our relationship with it that guide one''s decisions","The decisions that we make when dealing with the environment"]', 2, 'An individual''s or group''s environmental value system is a combination of values and ideas that determine how they look at and act upon environmental issues. Like any other system, an EVS has inputs and outputs.', 'Environmental Value Systems', 'easy', '1'),
('ess_m1_23', 'Identify the statement about a systems diagram that is true.', '["Storages are drawn as rectangles","Flows are shown with lines","Flows show the movement of matter only","The size of the rectangles does not matter"]', 0, 'Storages are shown as rectangles, often with the name of the storage written in it. Option B is incorrect, as flows are shown with arrows which show where the flow goes to. Option C is incorrect, as flows may show the movement of energy.', 'Systems and Models', 'easy', '1'),
('ess_m1_24', 'In the model of the carbon cycle, identify the flows or processes which increase the carbon dioxide in the atmosphere.', '["Combustion and respiration","Photosynthesis and consumption of producers by consumers","Photosynthesis","Death and fossilization"]', 0, 'During combustion, fossil fuels are burnt and release large quantities of carbon dioxide into the atmosphere, leading to global warming. Respiration also releases carbon dioxide to the atmosphere. Photosynthesis (Option C) takes carbon dioxide out of the atmosphere.', 'Humans and Pollution', 'easy', '1'),
('ess_m1_25', 'Identify which of the following best represents stage II in the development of an environmental value system as represented in the system diagram.', '["Research for a project on ways of reducing carbon footprints","The country a person lives in","A person''s religion","Joining your school''s environmental action club"]', 0, 'Option B is best classified as an input, as would option C. Option D is best classified as an output. Option A best represents a process in a system of value development.', 'Environmental Value Systems', 'medium', '1'),
('ess_m1_26', 'Explain the idea that the environment has an intrinsic value.', '["The environment is beautiful and should therefore be protected","The environment is useful and should therefore be valued","The environment is a system that includes us and therefore should be protected","The environment exists and therefore should be valued"]', 3, 'Intrinsic means basic to a thing, an aspect that belongs to a thing. Intrinsic value means that something is valuable simply for being what it is. Option D is correct. The environment has value in just being, not for what it can provide.', 'Environmental Value Systems', 'medium', '1'),
('ess_m1_27', 'Identify which of the following is not true of a systems diagram.', '["Storages and flows are shown as boxes and arrows","Flows shown as arrows indicate transfers that show a change in location","Sizes of the boxes show magnitudes of the flows of matter","Flows shown as arrows indicate transformations that show a change in state"]', 2, 'Boxes show magnitudes of storages of matter. Boxes are used in systems diagrams to show storages. Flows are shown as arrows in systems diagrams (Option A). Options B and D are both flows shown as arrows to indicate transfers and transformations.', 'Systems and Models', 'medium', '1'),
('ess_m1_28', 'The Figure shows the population density cycles of a predator and prey. Describe the relationship between the two animals.', '["No relationship between predator and prey","Negative feedback maintaining a stable equilibrium","Positive feedback maintaining a stable equilibrium","Positive feedback going away from the initial equilibrium"]', 1, 'Negative feedback is when an initial change to a system leads to a response that reduces that change and brings the system back to the original state. Negative feedback is important in maintaining a stable equilibrium.', 'Energy and Equilibria', 'medium', '1'),
('ess_m1_29', 'Identify which term best describes the difference indicated by the yellow arrow.', '["Exploitation","Overshoot","Collapse","Sustainable harvesting"]', 1, 'Option A is a judgment term that may be reflected in the graph, but this could easily be a natural level of consumption. Option B is correct as it is a term used to describe when an environment''s capacity to produce has been exceeded.', 'Sustainability', 'medium', '1'),
('ess_m1_30', 'An EIA is usually carried out before a major construction project. Outline its basic structure. I. Baseline studies to monitor changes. II. Assessment of social, economic and environmental impacts long term. III. Directions to observe indirect impacts of the project.', '["I only","II only","I and II only","III only"]', 2, 'An EIA is done to evaluate possible impacts and suggest mitigation strategies before a project is undertaken. It includes baseline studies and an assessment of the longterm impacts of the project (Statements I and II).', 'Humans and Pollution', 'medium', '1'),
('ess_m1_31', 'In 1984 the Union Carbide plant in Bhopal, India, released vast amounts of methyl isocyanate gas into the air. Thousands of people died. State the type of pollution that occurred.', '["Non-point source pollution","Non-point source pollution","Point source pollution","Point source pollution"]', 2, 'The pollution is released from a single place, so it is a point source. The pollution was released at one time, so it is acute. This means that Options A and B are incorrect, and Option C is the correct answer.', 'Humans and Pollution', 'medium', '1'),
('ess_m1_32', 'State which row does not correctly match the term and the example.', '["Primary pollutant","Point source pollutant","Persistent organic pollutant","Secondary pollutant"]', 1, 'Option B is incorrect as fossil fuels are burned in many places like cars and factories so it is difficult to narrow down its source to one point. Option A is a correct match as CO is a primary pollutant. Option C is a correct match.', 'Humans and Pollution', 'medium', '1'),
('ess_m1_33', 'Distinguish between transfers and transformations of carbon on the diagram of the carbon cycle. I. CO2 dissolving into the ocean  II. Photosynthesis converting CO2 to glucose', '["Transfer","Transfer","Transformation","Transformation"]', 0, 'A transfer of matter from one store to another occurs when the chemical makeup of the matter is unchanged. In example I, CO2 is dissolving into the ocean, which just means it is mixed in between the water molecules. A transformation involves a chemical change.', 'Systems and Models', 'easy', '1'),
('ess_m1_34', 'Identify which statements are most closely associated with an anthropocentric environmental value system. I. Technology is our best chance at stopping climate change. II. As humans, we are responsible to take care of the planet. III. Nature is inherently balanced and will restore itself. IV. Small-scale agriculture is more sustainable than large-scale agriculture.', '["I only","II only","II and IV","I, II, and IV"]', 2, 'Statement I is most associated with a technocentric EVS, while statement III is an ecocentric perspective. Both statements II and IV involve human-centred ideas for solutions to environmental problems.', 'Environmental Value Systems', 'medium', '1'),
('ess_m1_35', 'Deduce the processes represented by the flows of matter in the Figure. I. Respiration  II. Photosynthesis  III. Evapotranspiration  IV. Absorption', '["I and II only","III and IV only","I, II and IV only","I, II, III and IV"]', 3, 'Water, CO2 and sunlight are required for the process of photosynthesis. O2 is produced during photosynthesis. Heat is produced by the process of respiration in the cells of the tree. Water is absorbed by the root hairs.', 'Systems and Models', 'medium', '1'),
('ess_m1_36', 'Identify which of the following options about feedback is not correctly paired with the example.', '["Positive feedback cycle","Negative feedback cycle","Negative feedback cycle","Positive feedback cycle"]', 2, 'Negative feedback cycle will prevent an exponential increase in population numbers like in the predator prey cycle. Increased cloud cover (Option B) will decrease temperature, which will eventually decrease cloud cover — that is negative feedback.', 'Energy and Equilibria', 'medium', '1'),
('ess_m1_37', 'Identify the stage in succession that is most likely to show resilience and the ability to withstand changes.', '["Pioneer community when abiotic conditions are poor","Pioneer community with the growth of lichens and grasses","Intermediate stages of succession when consumers join the food chain","Climax community when food chains are fully developed"]', 3, 'Climax communities are reached when secondary productivity is at a maximum and complex food webs exist in the community. This community is stable and resilient to diseases and other unforeseen changes.', 'Energy and Equilibria', 'medium', '1'),
('ess_m1_38', 'The estimated population of Luxembourg is 640,000, while Brazil is estimated at 214 million. Calculate the total CO2 emissions in tonnes for both countries using the per capita data from the Figure.', '["Luxembourg: 1,779,200; Brazil: 597,540,000","Luxembourg: 1,734,400; Brazil: 580,140,000","Luxembourg: 2.78; Brazil: 2.71","Luxembourg: 278,000,000; Brazil: 640,000"]', 0, 'Multiply the population estimate by the amount per capita. Luxembourg = 640,000 x 2.78 = 1,779,200 tonnes. Brazil = 214,000,000 x 2.71 = ~580 million tonnes.', 'Humans and Pollution', 'medium', '1'),
('ess_m1_39', 'Identify the option in which the factor is not correctly paired with how it affects sustainability.', '["Increase in pollution levels","Increase in biodiversity","Increase in climate change","Increase in ecological footprint"]', 3, 'An increase in a person''s ecological footprint does not lead to sustainability as it means that more land is needed per capita to provide resources and assimilate waste. All other changes have been correctly paired with their effect.', 'Sustainability', 'medium', '1'),
('ess_m1_40', 'List the statements that are true about DDT: I. DDT has saved millions of lives in the battle against malaria. II. DDT is biomagnified along a food chain but does not bioaccumulate. III. DDT is a persistent organic pollutant (POP) that has been used effectively as an insecticide.', '["I only","I and III only","II and III only","I, II and III"]', 1, 'Malaria has been a major cause of death for thousands of years. DDT was so effective in killing the mosquitoes that transmit malaria that it has saved millions of lives since it was first made about 150 years ago (Statement I). DDT does bioaccumulate, so Statement II is incorrect. Statement III is correct.', 'Humans and Pollution', 'medium', '1'),
('ess_m1_41', 'The model in the Figure shows how sea level changes in a salt marsh area could affect the sequestration (capture) of carbon. Outline the disadvantages of using models to make predictions. I. Models do not accommodate all factors involved. II. Models use data that may not be the most accurate. III. Models are oversimplified for understanding and therefore misleading.', '["Statement I only","Statements I and II only","Statement III only","Statements I, II and III"]', 3, 'All the statements are true and explain the problems using models, to predict what may happen in time to come.', 'Systems and Models', 'medium', '1'),
('ess_m1_42', 'Determine which of the following terms could describe the people taking part in the demonstration shown in this image.', '["Anthropocentrics","Ecocentrics","Technocentrics","All of the above"]', 3, 'One''s environmental value system informs their ideas on the place the environment holds on the earth and how we can approach solutions to issues surrounding the environment. People with any of the environmental value systems could take part.', 'Environmental Value Systems', 'hard', '1'),
('ess_m1_43', 'As a young 12-year-old girl, Severn Suzuki spoke at the Earth Summit in Rio in 1992. Describe how she may have shaped the outcomes. I. Government leaders were made aware of the impact of environmental degradation on the next generation. II. Legislation was written to tackle the hole in the ozone. III. People around the world realised that raising their voices could influence decisions at the Rio Earth Summit.', '["I only","II only","I and III only","I, II and III"]', 0, 'Statement I is true. Individuals can stand up and influence people''s actions, both in their personal lives as well as their professional lives. Statement II refers to the Montreal Protocol, not the Rio Summit. Statement III overstates the direct effect of one speech.', 'Environmental Value Systems', 'hard', '1'),
('ess_m1_44', 'Wangari Maathai received the Nobel Peace Prize in 2004 for her efforts in sustainable development. Since 1977 the Green Belt Movement she started encouraged women to plant trees to combat desertification in Kenya and Africa. Identify which environmental value system best matches her description.', '["Deep ecologist","Anthropocentric","Technocentric","Materialistic"]', 1, 'Of these options, the best match for the description of Wangari Maathai is anthropocentric, option B. She encouraged the women to sustainably manage their environment through local, practical actions.', 'Environmental Value Systems', 'hard', '1'),
('ess_m1_45', 'Identify the inputs and outputs of matter and energy for a tree. I. Water  II. Sunlight  III. Heat  IV. CO2  V. O2', '["I, II, III and IV","II","II and V","II and IV"]', 1, 'The process of photosynthesis requires sunlight, CO2 and water and produces glucose and O2. The process of respiration requires glucose and O2 and produces CO2, water and heat. Sunlight is the only pure input (not also an output).', 'Systems and Models', 'hard', '1'),
('ess_m1_46', 'Identify which of the following is an example of transformation.', '["Water is lost from plants by the process of transpiration (evaporation from the leaves)","During photosynthesis, carbon dioxide moves into the leaves of the plants","Producers are consumed by herbivores in ecosystems","Glucose and other sugars made in the leaves are transported to other parts of the plant"]', 0, 'Option A is correct because it involves a change of state: water is lost by evaporation. All other choices are a movement of matter from one place to another. Transfer of matter refers to the change in location, and transformation of matter refers to a change of state.', 'Systems and Models', 'medium', '1'),
('ess_m1_47', 'Determine which of the following sequences is an example of a negative feedback mechanism.', '["Deforestation leads to less CO2 absorption leads to more warming","Increase in temperature leads to more evaporation leads to more cloud cover leads to cooling","Increase in primary production leads to more food leads to population growth","Thawing of permafrost releases methane leads to more warming"]', 1, 'Negative feedback loops will negate the change and bring the system back to the original, maintaining an equilibrium with small fluctuations. Positive feedback loops will destabilize the system and amplify the changes. Only option B describes a negative feedback loop.', 'Energy and Equilibria', 'hard', '1'),
('ess_m1_48', 'Identify the factor that is not a way to increase sustainability.', '["Decreasing genetic diversity due to the use of monocultures for food production","Increasing biodiversity leading to increased resilience to invasive species","Decreasing effects of climate change due to increase in forests and wetland areas","Improving crop production by introducing bees and other pollinators"]', 0, 'An increase in genetic diversity is necessary for breeding programs and developing new varieties of crops. Genetic diversity also provides resilience to changes and creates sustainable agricultural systems. Decreasing it (option A) reduces sustainability.', 'Sustainability', 'hard', '1'),
('ess_m1_49', 'Some sunscreens contain chemicals such as zinc (Zn) that may be toxic to some marine life. The figure shows the concentration of zinc in seawater at Palmira Beach on Majorca over the course of a day. Suggest the most likely conclusion.', '["Zinc is harmful to organisms found in the surface microlayer","Zinc mixes freely in the water after it washes off the skin","Zinc is absorbed and rendered harmless during the night","The total concentration of zinc in the surface microlayer is highest soon after many people will have started using sunscreen"]', 3, 'Option D is correct as we see on the graph that both zinc in the surface microlayer as in the subsurface layer is highest at 14:00. Most people use sunscreen when the sun is high in the sky. It is highest at noon, 2 hours before the highest concentration.', 'Humans and Pollution', 'hard', '1'),
('ess_m1_50', 'The population of Egypt was approximately 100 million in 2019. Calculate approximately how many people in Egypt died from outdoor air pollution in that year.', '["160,000 people","160 people","1000 people","1600 people"]', 0, 'Deaths 100,000 = (deaths / total population) x 100,000. Total deaths = 160 per 100,000 x (100,000,000 / 100,000) = 160 x 1,000 = 160,000 total deaths.', 'Humans and Pollution', 'hard', '1'),
('ess_m1_51', 'Consider the following list of influential events: I. Al Gore''s book An Inconvenient Truth  II. Rachel Carson''s book Silent Spring  III. The Fukushima Nuclear Disaster  IV. The Chernobyl Nuclear Disaster. Deduce the correct order from earliest to latest.', '["I, II, III, IV","II, IV, I, III","II, I, III, IV","IV, I, III, II"]', 1, 'I. Published 2006. II. Published 1962. III. Occurred in 2011. IV. Occurred in 1986. So the correct chronological order is: II (1962), IV (1986), I (2006), III (2011).', 'Environmental Value Systems', 'hard', '1'),
('ess_m1_52', 'Using CO2 emissions data from deforestation for food production (2010-2014), suggest which statements are supported. I. China and the U.S. had low CO2 emissions. II. Brazil and Luxembourg had high CO2 emissions. III. France and Spain had the same amount of CO2 emissions.', '["All statements are supported by the information","Statements II and III are supported","Only statement III is supported","None of the statements are supported"]', 3, 'Statement I is not supported because the value here is per capita for only one source of emissions. Both of these countries have high populations and are world leaders on CO2 emissions from other sources. Statement II and III are also not fully supported by the per capita data.', 'Humans and Pollution', 'hard', '1');

-- ─── WRITTEN QUESTIONS ─────────────────────────────────────
INSERT OR IGNORE INTO ess_written_questions (id, question, mark_scheme, marks, type, category, difficulty, unit) VALUES
('ess_w1_01', 'Distinguish between ecocentric, anthropocentric, and technocentric environmental value systems. For each, provide one example of how a person with that EVS might approach the issue of deforestation.', 'Ecocentrism: nature-centered; would oppose deforestation, advocate for intrinsic value of forests and biodiversity. [1] Anthropocentrism: human-centered but sustainable; would allow some logging if managed sustainably with replanting. [1] Technocentrism: technology-centered; would support deforestation if technology can provide alternatives or mitigate damage. [1] Example for each. [1 each = 3] Award [1] for correctly defining each EVS, [1] for a relevant example for each. [max 6]', 6, 'long', 'Environmental Value Systems', 'medium', '1'),
('ess_w1_02', 'Explain the difference between positive and negative feedback loops, using one named environmental example for each.', 'Positive feedback: amplifies or reinforces change, moves system away from equilibrium. [1] Example: Arctic ice melting — less ice means less albedo (reflection), more heat absorbed, more melting. [1-2] Negative feedback: counteracts change, returns system toward equilibrium. [1] Example: Increased CO2 leads to increased plant growth, which absorbs more CO2. [1-2] Clear distinction and correct terminology. [max 5]', 5, 'long', 'Energy and Equilibria', 'medium', '1'),
('ess_w1_03', 'Define sustainability and explain how the ecological footprint can be used to evaluate the sustainability of a population.', 'Sustainability: meeting the needs of the present without compromising future generations'' ability to meet their own needs (Brundtland). [1] Ecological footprint: area of land/water needed to sustain a population and absorb its waste. [1] If footprint exceeds biocapacity, the population is living unsustainably. [1] Comparison between nations — developed nations often have larger footprints. [1] Can be used to set targets for reducing consumption. [1] [max 4]', 4, 'long', 'Sustainability', 'medium', '1'),
('ess_w1_04', 'With reference to systems thinking, explain the concepts of inputs, outputs, storages, and flows. Use one named ecosystem as an example.', 'Inputs: matter/energy entering a system (e.g., solar energy, precipitation). [1] Outputs: matter/energy leaving (e.g., heat loss, river flow out). [1] Storages: where matter/energy is held (e.g., biomass, soil nutrients). [1] Flows/transfers: movement of matter/energy between storages (e.g., nutrient uptake by plants). [1] Named ecosystem example correctly applied. [1] [max 5]', 5, 'long', 'Systems and Models', 'medium', '1'),
('ess_w1_05', 'Outline the strengths and limitations of using models to represent environmental systems.', 'Strengths: simplify complex reality for understanding [1]; allow predictions to be made [1]; can be tested and refined [1]. Limitations: oversimplify reality [1]; may not account for all variables [1]; based on assumptions that may not hold [1]; predictions may be inaccurate [1]. [max 4]', 4, 'long', 'Systems and Models', 'medium', '1');
